import{_ as a,c as e,o as i,ah as r,ai as o,aj as s,ak as h}from"./chunks/framework.C1fN9oMS.js";const d=JSON.parse('{"title":"github 仓库的建立","description":"","frontmatter":{},"headers":[],"relativePath":"git/note1.md","filePath":"git/note1.md"}'),g={name:"git/note1.md"};function n(b,t,p,l,u,c){return i(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="github-仓库的建立" tabindex="-1">github 仓库的建立 <a class="header-anchor" href="#github-仓库的建立" aria-label="Permalink to “github 仓库的建立”">​</a></h1><p>首先建立一个github的账号 网址是 <a href="https://github.com/" target="_blank" rel="noreferrer">https://github.com/</a></p><br><h2 id="仓库的创建" tabindex="-1">仓库的创建 <a class="header-anchor" href="#仓库的创建" aria-label="Permalink to “仓库的创建”">​</a></h2><p>名称最好使用自己的用户名后面还要打上 .github.io</p><br><p><img src="'+o+'" alt="2.png"></p><p>未来将自己在电脑上写的代码同步到github创建的仓库中要提前安装 git bash x64位的电脑安装Git/x64的安装包</p><p><img src="'+s+'" alt="3.png"></p><br><h2 id="密钥的获取" tabindex="-1">密钥的获取 <a class="header-anchor" href="#密钥的获取" aria-label="Permalink to “密钥的获取”">​</a></h2><p>密钥可以将自己的电脑和github 账号联系在一起后面就可以通过git bash 将 代码上传</p><h3 id="密钥的获取方式" tabindex="-1">密钥的获取方式 <a class="header-anchor" href="#密钥的获取方式" aria-label="Permalink to “密钥的获取方式”">​</a></h3><p>首先在本地文件夹里面新创建一个文件夹命名为 key 打开 git bash 唤出控制面板</p><br><br><p><img src="'+h+'" alt="4.png"></p><p>输入 ssh-keygen -t rsa -C &quot;输入注册github时使用的邮箱&quot;注意ssh-keygen 之间没有空格而且C要大写</p><br><p>找到密钥存储的位置打开.ssh后缀的文件夹打开.pub后缀的文件里面就是密钥，复制密钥在settings找到SSHandGPGkeys中创建密钥 在key中输入刚刚复制的密钥点击addSSHkey在打开gitbash 输入ssh -T <a href="mailto:git@github.com" target="_blank" rel="noreferrer">git@github.com</a>,在输入yes出现下面的界面就说明链接成功了 输入git confing --global user.name &quot;这里输入用户名&quot; 输入git confing --global user.email &quot;这里输入注册github账号的邮箱&quot; 克隆仓库 在github中打开创建的仓库，复制仓库的网址在文件夹里面创建一个boke文件夹然后复制这个文件夹的路径 打开git bash 输入cd / 刚刚复制的文件夹路径回车 在输入 gitclone后面接上刚刚复制的仓库网址成功后会出现一个和git里面仓库名字相同的文件夹 输入ls可以查看定位的文件夹里面的文件 输入 git add &quot;这里面输入要上传的文件的名称&quot; 输入 git commit -m &quot;这里面输入你对刚刚上传的文件的备注&quot; 在输入git push origin main 出现以下界面就说明成功了 在github中仓库中就可以看到文件</p>',20)])])}const _=a(g,[["render",n]]);export{d as __pageData,_ as default};
